int x264_slice_write( x264_t *h, x264_nal_t *nal, x264_picture_t *pic, x264_pts_t pts, x264_pts_t dts, int i_nal )
{
    x264_encoder_slice_t *slice;
    int i_slice_size = 0;

    // 如果不是VFR模式并且每个GOP输出的帧数已经达到了FPS分母，则更新总帧数，重置帧数计数器，更新FPS
    if( !h->param.b_vfr_input && h->i_num_output % h->param.i_fps_den == 0 )
    {
        h->i_frame_total += h->i_num_output;
        h->i_num_output = 0;
        x264_update_fps( h, h->i_num_output );
    }

    // 如果是VFR模式并且b_force_idr标志没有设置
    if( h->param.b_vfr_input && !h->b_force_idr )
    {
        // 如果当前帧是关键帧，或者当前帧是下一个VFR输入，则强制设置下一帧为IDR帧
        if( h->i_next_vfr_input == h->i_num_output && (h->frame_num % h->sps.i_frame_max_num) == 0 )
            h->b_force_idr = 1;
    }

    // 获取当前NAL单元类型的x264_encoder_slice_t结构体
    slice = &h->out.bframes[ nal->i_payload ? !!nal->i_type : (NAL_SLICE_TYPE_IDR == nal->i_type) ];

    // 设置分片标志位
    slice->i_flags &= ~X264_SLICE_TYPEMASK;
    slice->i_flags |= (NAL_SLICE_TYPE_IDR == nal->i_type)*X264_SLICE_TYPE_IDR + (x264_nal_is_keyframe( nal ) ? X264_SLICE_TYPE_KEYFRAME : X264_SLICE_TYPE_PFRAME);

    // 设置分片的帧号、标志位和参考帧数
    slice->i_frame_num = h->i_frame_num;
    slice->i_field_pic_flag = 0;
    slice->i_nal_references = pic->b_reference ? h->i_nal_reference : 0;

    // 设置分片的起始和结束MB地址
    if( h->param.i_slice_count == 0 )
    {
        slice->i_first_mb_addr = 0;
        slice->i_end_mb_addr = h->sps.i_mb_width*h->sps.i_mb_height-1;
    }
    else
    {
        slice->i_first_mb_addr = x264_clip3f( 0, h->sps.i_mb_width*h->sps.i_mb_height-2, nal->i_first_mb );
        slice->i_end_mb_addr = x264_clip3f( 1, h->sps.i_mb_width*h->sps.i_mb_height-1, nal->i_first_mb + nal->i_last_mb );
    }

    // 打印调试信息
    x264_dbg( h, X264_DBG_SPSPPS, "PTS %"PRId64", DTS %"PRId64", frame=%d, type=%c%cx%d, num_output=%d (%d): forcing %d (%d)\n",
                pts, dts, h->i_frame_num, x264_nal_is_long_startcode( nal ) ? '$' : ' ', x264_nal_get_type( nal ), slice->i_frame_num, h->i_num_output, slice->i_flags & X264_SLICE_TYPEMASK, !!h->b_force_idr );

    if( nal->i_payload > 0 )
    {
        // 使用realloc函数为分片分配新的缓存
        i_slice_size = nal->i_payload;
        slice->p_payload = (uint8_t*)x264_realloc( slice->p_payload, i_slice_size );

        // 将NAL数据拷贝到分片的paylaod中
        memcpy( slice->p_payload, nal->p_payload, i_slice_size );
    }
    else
    {
        slice->p_payload = NULL;
        i_slice_size = 0;
    }

    // 设置分片的PTS和DTS，取最小值
    slice->i_pts = slice->i_dts = x264_min( pts, dts );
    slice->i_length = i_slice_size;
    return i_slice_size;
}

